//go:build integration

package testchain

// ensbytecode.go is the compiled creation bytecode for the M7 mock ENS contract
// (testchain/MockENS.sol — a minimal combined ENS registry + public resolver):
//
//	mapping(bytes32 => address) addrOf;      // node => address (resolver.addr)
//	mapping(bytes32 => string)  nameOf;      // node => name    (resolver.name / reverse)
//	mapping(bytes32 => address) resolverOf;  // node => resolver (registry.resolver)
//	resolver(bytes32) -> resolverOf[node] or address(this)  // registry doubles as resolver
//	addr(bytes32) / name(bytes32)                            // public resolver reads
//	setAddr / setName / setResolver                          // test-only writers
//
// Compiled with Solc 0.8.26 via `forge build` from the source in DeployENS's doc
// comment. Pinned as a constant (the same pattern as erc20bytecode.go) so the
// integration suite needs no solc on the CI runner. Compiled only under
// `go test -tags integration`.
const ensBytecodeHex = ""
